-- ============================================================
-- Source migration: 20260704130000_enforce_max_claims_atomic.sql
-- ============================================================

-- Atomically enforce deals.max_claims on INSERT into deal_claims.
--
-- The claim-deal edge function does a SELECT-count followed by an INSERT with no
-- locking in between. Two concurrent claims at the cap boundary can both pass the
-- count check and both insert, overshooting the cap by N-1. This trigger locks
-- the parent deal row with FOR UPDATE during each INSERT, serializing concurrent
-- claim inserts per-deal so the count reflects every committed and in-flight
-- sibling. The edge function's pre-check is kept as a fast path; the trigger is
-- now the authoritative gate.

CREATE OR REPLACE FUNCTION enforce_deal_max_claims()
RETURNS trigger
LANGUAGE plpgsql
AS $$
DECLARE
  deal_max INTEGER;
  current_count INTEGER;
BEGIN
  -- Lock the parent deal row for the duration of this transaction. Concurrent
  -- inserts for the same deal_id serialize here.
  SELECT max_claims INTO deal_max
  FROM deals
  WHERE id = NEW.deal_id
  FOR UPDATE;

  -- NULL or <= 0 means unlimited (matches the edge-function convention at
  -- supabase/functions/claim-deal/index.ts:483).
  IF deal_max IS NULL OR deal_max <= 0 THEN
    RETURN NEW;
  END IF;

  -- Count the same way the edge function counts: everything except 'canceled'.
  SELECT count(*) INTO current_count
  FROM deal_claims
  WHERE deal_id = NEW.deal_id
    AND claim_status != 'canceled';

  IF current_count >= deal_max THEN
    RAISE EXCEPTION 'MAX_CLAIMS_REACHED' USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_enforce_deal_max_claims ON deal_claims;
CREATE TRIGGER trg_enforce_deal_max_claims
  BEFORE INSERT ON deal_claims
  FOR EACH ROW
  EXECUTE FUNCTION enforce_deal_max_claims();


-- ============================================================
-- Source migration: 20260705120000_businesses_pii_column_grants.sql
-- ============================================================

-- Restrict consumer read access on the public `businesses` table to non-PII columns.
--
-- Before this migration, the policy "Anyone can read businesses" USING (true) let any
-- authenticated session read every column, including business_email, contact_name, tone,
-- and the owner's auth.users uuid. The consumer feed and business detail page only need a
-- safe subset; owners need full read access via a separate SECURITY DEFINER function.
--
-- Strategy:
--   1. Keep the row-level policy permissive (consumers still see all rows).
--   2. Add column-level GRANTs that exclude PII from anon/authenticated.
--   3. Provide get_my_business() for owners to read their own row in full.

REVOKE SELECT ON public.businesses FROM anon, authenticated;

GRANT SELECT (
  id,
  name,
  address,
  location,
  latitude,
  longitude,
  phone,
  hours_text,
  short_description,
  category,
  preferred_locale,
  logo_url,
  website,
  instagram_handle,
  facebook_url,
  pickup_note,
  created_at
) ON public.businesses TO anon, authenticated;

-- Note: business_email, contact_name, tone, owner_id remain ungranted to anon/authenticated.

-- Owners read their own row (including PII) via this SECURITY DEFINER function.
CREATE OR REPLACE FUNCTION public.get_my_business()
RETURNS SETOF public.businesses
LANGUAGE sql
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT * FROM public.businesses WHERE owner_id = auth.uid() LIMIT 1;
$$;

-- Supabase default privileges grant EXECUTE to anon on every new function, and
-- REVOKE FROM PUBLIC does not remove that explicit grant (verified live on
-- 2026-06-10 with purge_user_data / deal_claim_counts). Revoke anon explicitly.
REVOKE EXECUTE ON FUNCTION public.get_my_business() FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.get_my_business() TO authenticated;

COMMENT ON FUNCTION public.get_my_business()
  IS 'Returns the caller''s business row with all columns (including PII). Bypasses column-level GRANT restrictions via SECURITY DEFINER. Use this in owner-side code instead of querying `businesses` directly.';


-- ============================================================
-- Source migration: 20260705120002_deal_claims_unique_active.sql
-- ============================================================

-- Prevent duplicate active claims per (user, deal).
--
-- Before: claim-deal checked "is null redeemed_at" then inserted, but two concurrent
-- requests from the same user (e.g. double-tap claim button) both passed the check and
-- inserted. The edge function's "23505 -> already have an active claim" branch was
-- relying on a constraint that didn't exist.
--
-- This is a partial unique index so it only constrains active/redeeming rows. Canceled
-- and expired claims can pile up indefinitely (existing canceled rows are preserved).

-- Pre-check: refuse to apply if existing data violates the constraint.
DO $$
DECLARE
  v_dupes integer;
BEGIN
  SELECT count(*)
    INTO v_dupes
    FROM (
      SELECT user_id, deal_id, count(*) AS n
        FROM public.deal_claims
        WHERE claim_status IN ('active', 'redeeming')
        GROUP BY user_id, deal_id
        HAVING count(*) > 1
    ) AS dupes;

  IF v_dupes > 0 THEN
    RAISE EXCEPTION
      'Cannot create unique index: % (user_id, deal_id) pairs have duplicate active/redeeming claims. Clean up before applying this migration.',
      v_dupes;
  END IF;
END $$;

CREATE UNIQUE INDEX IF NOT EXISTS deal_claims_one_active_per_user_deal
  ON public.deal_claims (user_id, deal_id)
  WHERE claim_status IN ('active', 'redeeming');

COMMENT ON INDEX public.deal_claims_one_active_per_user_deal
  IS 'Prevents the same user from holding multiple active or redeeming claims on the same deal. Enforced at the DB level so concurrent double-tap claims fail cleanly with SQLSTATE 23505.';


-- ============================================================
-- Source migration: 20260705120004_deal_claims_dashboard_index.sql
-- ============================================================

-- Speed up the merchant dashboard "active claims" widget and the analytics rollups
-- that filter by (deal_id, claim_status). At 1000+ claims/day per cafe the existing
-- single-column indexes start to require sequential scans for status-filtered queries.

CREATE INDEX IF NOT EXISTS idx_deal_claims_deal_status
  ON public.deal_claims (deal_id, claim_status)
  WHERE claim_status IN ('active', 'redeeming');

COMMENT ON INDEX public.idx_deal_claims_deal_status
  IS 'Partial index supporting dashboard active-claims queries and the max_claims trigger''s recount.';


-- ============================================================
-- Source migration: 20260705120005_business_profiles_single_row.sql
-- ============================================================

-- Prevent a single user from holding multiple business_profiles rows via the dual-key
-- (user_id, owner_id) pattern.
--
-- Existing constraints: separate UNIQUE on user_id and on owner_id. A user_id-only row
-- and an owner_id-only row for the same auth user are both legal today, leading to

-- Pre-check: refuse to apply if existing data already has duplicates.
DO $$
DECLARE
  v_dupes integer;
BEGIN
  SELECT count(*)
    INTO v_dupes
    FROM (
      SELECT COALESCE(user_id, owner_id) AS auth_user, count(*) AS n
        FROM public.business_profiles
        WHERE user_id IS NOT NULL OR owner_id IS NOT NULL
        GROUP BY COALESCE(user_id, owner_id)
        HAVING count(*) > 1
    ) AS dupes;

  IF v_dupes > 0 THEN
    RAISE EXCEPTION
      'Cannot create unique index: % auth users own multiple business_profiles rows. Merge them before applying this migration.',
      v_dupes;
  END IF;
END $$;

CREATE UNIQUE INDEX IF NOT EXISTS business_profiles_one_per_auth_user
  ON public.business_profiles (COALESCE(user_id, owner_id))
  WHERE user_id IS NOT NULL OR owner_id IS NOT NULL;

COMMENT ON INDEX public.business_profiles_one_per_auth_user
  IS 'Ensures a single business_profiles row per auth user regardless of whether it is keyed by user_id, owner_id, or both. Companion to the existing UNIQUE constraints on each column individually.';


-- ============================================================
-- Source migration: 20260705120006_realtime_publication_insert_only.sql
-- ============================================================

-- Restrict the supabase_realtime publication to INSERT events only.
--
-- Before: 20260704120000_enable_deals_realtime.sql added the deals table with the default
-- publish list (insert, update, delete, truncate). Consumer clients subscribed to INSERT
-- only, but every UPDATE on a deal (e.g. is_active toggles, claim count updates if those
-- are added later, merchant edits to title/description) was still broadcast over the
-- replication slot to all subscribed sessions, leaking merchant draft state.
--
-- The publication currently contains only `deals`, so applying the filter at the
-- publication level (instead of per-table) is safe today. If other tables are added to
-- the realtime publication later, this filter will affect them too — verify before adding.

ALTER PUBLICATION supabase_realtime SET (publish = 'insert');




-- ============================================================
-- Source migration: 20260705120007_failed_redeem_attempts.sql
-- ============================================================

-- Track failed redemption attempts (wrong/unknown short codes) to prevent brute-force
-- harvesting of valid codes by malicious merchants.
--
-- The redeem-token edge function will:
--   1. Insert a row here on every redemption attempt with `success = false`.
--   2. Before processing each attempt, count rows with success=false in the last 5 minutes
--      keyed on (business_id, ip_address). If >= 10, lock out with a 429.

CREATE TABLE IF NOT EXISTS public.failed_redeem_attempts (
  id            uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id   uuid        NOT NULL REFERENCES public.businesses(id) ON DELETE CASCADE,
  ip_address    inet,
  user_id       uuid        REFERENCES auth.users(id) ON DELETE SET NULL,
  attempted_at  timestamptz NOT NULL DEFAULT now(),
  reason        text        NOT NULL  -- 'unknown_code', 'expired', 'wrong_business', etc.
);

CREATE INDEX IF NOT EXISTS idx_failed_redeem_attempts_lookup
  ON public.failed_redeem_attempts (business_id, attempted_at DESC);

CREATE INDEX IF NOT EXISTS idx_failed_redeem_attempts_ip_lookup
  ON public.failed_redeem_attempts (business_id, ip_address, attempted_at DESC)
  WHERE ip_address IS NOT NULL;

ALTER TABLE public.failed_redeem_attempts ENABLE ROW LEVEL SECURITY;

-- Service role only — clients must never read or write this table directly.
-- (No policies = locked down by RLS default-deny.)

COMMENT ON TABLE public.failed_redeem_attempts
  IS 'Append-only log of failed token/code redemption attempts. Used by redeem-token to enforce per-business per-IP rate limiting.';


-- ============================================================
-- Source migration: 20260705120008_purge_user_data_rpc.sql
-- ============================================================

-- Deletes all consumer data owned by a given auth user.
--
-- Used by the delete-user-account edge function. Before this migration, that function
-- only called auth.admin.deleteUser() and relied on FK ON DELETE CASCADE — but several
-- tables (consumer_profiles, push_tokens, app_analytics_events, favorites, deal_claims)
-- have ON DELETE SET NULL or no cascade defined, so PII (birthdate, lat/lng, push tokens)
-- survived the auth deletion.
--
-- This RPC is the explicit purge step. Call it from delete-user-account BEFORE deleting
-- the auth row. Wrapped as SECURITY DEFINER so the edge function can call it without
-- needing direct table-level DELETE grants.

CREATE OR REPLACE FUNCTION public.purge_user_data(p_user_id uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Anonymize claim history (preserve aggregate analytics; remove personal link).
  UPDATE public.deal_claims
    SET user_id = NULL,
        zip_at_claim = NULL,
        location_source_at_claim = NULL
    WHERE user_id = p_user_id;

  -- Anonymize raw analytics events (keep the row for merchant dashboards but drop the link).
  UPDATE public.app_analytics_events
    SET user_id = NULL,
        session_id = NULL
    WHERE user_id = p_user_id;

  -- Hard-delete tables that exist purely for the user.
  DELETE FROM public.favorites WHERE user_id = p_user_id;
  DELETE FROM public.push_tokens WHERE user_id = p_user_id;
  DELETE FROM public.consumer_profiles WHERE user_id = p_user_id;

  EXECUTE 'DELETE FROM public.consumer_push_prefs WHERE user_id = $1'
    USING p_user_id;
EXCEPTION
  WHEN undefined_table THEN
    -- Table may not exist in all environments; ignore.
    NULL;
END;
$$;

REVOKE EXECUTE ON FUNCTION public.purge_user_data(uuid) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.purge_user_data(uuid) TO service_role;

COMMENT ON FUNCTION public.purge_user_data(uuid)
  IS 'Anonymizes or deletes all rows tied to a given auth user. Called by delete-user-account before auth.admin.deleteUser. Service role only.';


-- ============================================================
-- Source migration: 20260706120000_business_invite_gate.sql
-- ============================================================

-- Pilot-stage gate against random users signing up as a business and listing a
-- cafe they don't own. Only users who've validated the shared pilot invite code
-- (see lib/business-invite.ts) can create rows in `businesses`. Existing pilot
-- accounts are backfilled so they aren't locked out of editing.

BEGIN;

CREATE TABLE IF NOT EXISTS public.business_invite_validations (
  user_id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  validated_at timestamptz NOT NULL DEFAULT now(),
  code_used text NOT NULL
);

ALTER TABLE public.business_invite_validations ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS business_invite_self_read ON public.business_invite_validations;
CREATE POLICY business_invite_self_read
  ON public.business_invite_validations FOR SELECT
  USING (auth.uid() = user_id);

-- No client-side INSERT/UPDATE/DELETE policies — writes happen only through
-- public.validate_business_invite (SECURITY DEFINER below).

CREATE OR REPLACE FUNCTION public.validate_business_invite(invite_code text)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  uid uuid;
  normalized text;
BEGIN
  uid := auth.uid();
  IF uid IS NULL THEN
    RAISE EXCEPTION 'not authenticated' USING ERRCODE = '42501';
  END IF;
  normalized := lower(trim(coalesce(invite_code, '')));
  IF normalized <> 'penguin' THEN
    RAISE EXCEPTION 'invalid invite code' USING ERRCODE = '22023';
  END IF;
  INSERT INTO public.business_invite_validations(user_id, validated_at, code_used)
  VALUES (uid, now(), normalized)
  ON CONFLICT (user_id) DO NOTHING;
END;
$$;

REVOKE ALL ON FUNCTION public.validate_business_invite(text) FROM public;
GRANT EXECUTE ON FUNCTION public.validate_business_invite(text) TO authenticated;

-- Backfill: every existing business owner is treated as already validated so
-- pilot cafes that signed up before this migration aren't blocked from editing.
INSERT INTO public.business_invite_validations(user_id, validated_at, code_used)
SELECT DISTINCT owner_id, now(), 'pilot_backfill'
FROM public.businesses
WHERE owner_id IS NOT NULL
ON CONFLICT (user_id) DO NOTHING;

CREATE OR REPLACE FUNCTION public.businesses_require_invite()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM public.business_invite_validations
    WHERE user_id = COALESCE(NEW.owner_id, auth.uid())
  ) THEN
    RAISE EXCEPTION 'business invite required' USING ERRCODE = '42501';
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS businesses_require_invite_trg ON public.businesses;
CREATE TRIGGER businesses_require_invite_trg
  BEFORE INSERT ON public.businesses
  FOR EACH ROW EXECUTE FUNCTION public.businesses_require_invite();

COMMIT;


