-- ============================================================
-- Source migration: 20260707130000_align_strong_deal_guard_with_client.sql
-- ============================================================

-- Align the server strong-deal guardrail with the client mirror in
-- lib/strong-deal-guard.ts. The previous SQL was STRICTER than the client for
-- several legitimate strong-deal phrasings, so the client let owners hit Publish
-- but the row trigger then RAISEd — surfacing only a generic "Publish failed".
--
-- Confirmed divergences (client PASS / old server REJECT), verified read-only
-- against prod via scripts/probe-strong-deal.mjs:
--   * free item with trailing punctuation — "...second pastry is free!"
--     (old `LIKE '% free %'` required a space on BOTH sides)
--   * Spanish / Korean free + BOGO language ("gratis", "2x1", Korean tokens, ...)
--   * "get one free", "1+1"
--
-- This keeps the guardrail's INTENT intact (weak deals are still rejected); it
-- only stops valid strong deals from being wrongly blocked. Priority order
-- matches the client exactly:
--   1. FREE ITEM            -> PASS
--   2. CONDITIONAL DISCOUNT -> REJECT  ("buy X + N% off Y", reward not free)
--   3. PERCENT FLOOR (<40)  -> REJECT
--   4. STRONG LANGUAGE      -> PASS
--   5. otherwise            -> REJECT

CREATE OR REPLACE FUNCTION public.is_strong_deal_offer(
  p_title TEXT,
  p_description TEXT
)
RETURNS BOOLEAN
LANGUAGE plpgsql
IMMUTABLE
AS $$
DECLARE
  v_text TEXT;
  v_match TEXT;
BEGIN
  v_text := lower(coalesce(p_title, '') || ' ' || coalesce(p_description, ''));

  -- 1. FREE ITEM ------------------------------------------------------------
  -- "free" preceded by whitespace/start and ended by a word boundary, so
  -- "free!", "free." and "free," all match while "sugar-free" / "caffeine-free"
  -- (hyphen before) and "freedom" (no boundary after) do not.
  IF v_text ~* '(^|\s)free\y'
     OR v_text ~* '\mon\s+the\s+house\M'
     OR v_text ~* '\mcomplimentary\M'
     -- Spanish (containment for accented/short tokens — no real superstrings)
     OR v_text ~* '\mgratis\M'
     OR v_text ~* 'cortesía'
     OR v_text ~* 'de\s+regalo'
     OR v_text ~* 'invita\s+la\s+casa'
     -- Korean (client uses bare containment — no word boundaries)
     OR v_text ~ '무료'        -- free
     OR v_text ~ '서비스'      -- service / on the house
     OR v_text ~ '공짜'        -- free
  THEN
    RETURN TRUE;
  END IF;

  -- 2. CONDITIONAL DISCOUNT -------------------------------------------------
  -- "buy X + N% off Y" — discount requires buying a different item, reward not
  -- free → reject (mirrors the client's "+" notation rule).
  IF v_text ~* 'buy\s+\S.{0,60}\s*\+\s*[0-9]{1,3}\s*%\s*off' THEN
    RETURN FALSE;
  END IF;

  -- 3. PERCENT FLOOR --------------------------------------------------------
  FOR v_match IN
    SELECT m[1] FROM regexp_matches(v_text, '([0-9]{1,3})\s*%', 'g') AS m
  LOOP
    IF v_match::INT < 40 THEN
      RETURN FALSE;
    END IF;
  END LOOP;

  -- 4. STRONG LANGUAGE ------------------------------------------------------
  IF v_text ~* '\mbogo\M'
    OR v_text ~* '2\s*[- ]?\s*for\s*[- ]?\s*1'
    OR v_text ~* '2\s*for\s*one'
    OR v_text ~* 'two\s*for\s*one'
    OR v_text ~* 'buy\s*one\s*get\s*one'
    OR v_text ~* 'buy\s*1\s*get\s*1'
    OR v_text ~* 'get\s+one\s+free'
    OR v_text ~* 'get\s+1\s+free'
    OR v_text ~* 'second\s+item\s+free'
    OR v_text ~* 'second\s+one\s+free'
    OR v_text ~* '2nd\s+item\s+free'
    OR v_text ~* 'second\s+half\s+off'
    OR v_text ~* 'second\s+\w+\s+half\s+off'
    OR v_text ~* '50\s*%\s*off\s+the\s+second'
    OR v_text ~* '(40|[4-9][0-9]|100)\s*%\s*off'
    -- Spanish strong language
    OR v_text ~* 'compra\s+uno?\M.*gratis'
    OR v_text ~* 'lleva(te)?\s+(otro|el\s+segundo).*gratis'
    OR v_text ~* '2\s*(x|por)\s*1'
    OR v_text ~* 'dos\s+por\s+uno'
    OR v_text ~* '[4-9][0-9]\s*%\s*(de\s+)?descuento'
    OR v_text ~* 'mitad\s+de\s+precio'
    OR v_text ~* 'el\s+segundo\s+a\s+mitad'
    -- Korean strong language
    OR v_text ~ '1\s*\+\s*1'              -- 1+1
    OR v_text ~ '[4-9][0-9]\s*%\s*할인'   -- NN% 할인 (discount)
    OR v_text ~ '하나\s*사면\s*하나'      -- buy one get one
    OR v_text ~ '반값'                    -- half price
  THEN
    RETURN TRUE;
  END IF;

  RETURN FALSE;
END;
$$;

-- Trigger function/attachment unchanged — re-create idempotently so the new
-- definition is picked up and the friendly message stays in place.
CREATE OR REPLACE FUNCTION public.enforce_strong_deal_only_guardrail()
RETURNS trigger
LANGUAGE plpgsql
AS $$
BEGIN
  IF NOT public.is_strong_deal_offer(NEW.title, NEW.description) THEN
    RAISE EXCEPTION
      'Every Twofer deal must be at least 40%% off or give something free — '
      'e.g. ''Buy a coffee, get a muffin free'' or ''2-for-1 lattes''. '
      'Conditional deals like ''buy X + 40%% off Y'' don''t qualify.';
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_enforce_strong_deal_only_guardrail ON public.deals;
CREATE TRIGGER trg_enforce_strong_deal_only_guardrail
BEFORE INSERT OR UPDATE OF title, description ON public.deals
FOR EACH ROW
EXECUTE FUNCTION public.enforce_strong_deal_only_guardrail();


-- ============================================================
-- Source migration: 20260708120000_deal_viewed_daily_idempotency.sql
-- ============================================================

-- Server-side idempotency for impressions.
--
-- The old consumer feed re-emitted `deal_viewed` for every visible deal on every
-- list recompute (search keystroke, favorite toggle, radius/segment change), which
-- inflated the "Impressions" number shown to paying cafes. The client now counts a
-- deal at most once per session via real viewport visibility; this migration adds a
-- durable backstop so repeat sessions in the same day cannot re-inflate the count.
--
-- Dedupe key: (user_id, deal_id, device_platform, UTC day). "Device" is the coarsest
-- signal we currently capture (device_platform); a user on two platforms still counts
-- once per platform per day, which matches "per user/device + deal + day".

-- 0) Safety backup of the FULL analytics table before the destructive de-dup below.
--    Runs in the same migration/transaction, so the backup is guaranteed to capture
--    the pre-cleanup state. Drop it once the deflated numbers are verified:
--      DROP TABLE IF EXISTS public.app_analytics_events_backup_20260708;
CREATE TABLE IF NOT EXISTS public.app_analytics_events_backup_20260708 AS
  SELECT * FROM public.app_analytics_events;

-- 1) Collapse historical duplicate deal_viewed rows so the unique index below can be
--    built, and so existing dashboards deflate to honest numbers. Keeps the earliest
--    row per group (lowest occurred_at, then lowest id).
DELETE FROM public.app_analytics_events a
USING public.app_analytics_events b
WHERE a.event_name = 'deal_viewed'
  AND b.event_name = 'deal_viewed'
  AND a.user_id IS NOT NULL
  AND a.deal_id IS NOT NULL
  AND a.user_id = b.user_id
  AND a.deal_id = b.deal_id
  AND COALESCE(a.device_platform, '') = COALESCE(b.device_platform, '')
  AND (a.occurred_at AT TIME ZONE 'UTC')::date = (b.occurred_at AT TIME ZONE 'UTC')::date
  AND (
    a.occurred_at > b.occurred_at
    OR (a.occurred_at = b.occurred_at AND a.id > b.id)
  );

-- 2) Enforce one deal_viewed per (user, deal, device_platform, UTC day) going forward.
--    Partial + expression index; the edge function treats a 23505 here as a no-op.
CREATE UNIQUE INDEX IF NOT EXISTS uq_app_analytics_deal_viewed_daily
  ON public.app_analytics_events (
    user_id,
    deal_id,
    COALESCE(device_platform, ''),
    ((occurred_at AT TIME ZONE 'UTC')::date)
  )
  WHERE event_name = 'deal_viewed'
    AND user_id IS NOT NULL
    AND deal_id IS NOT NULL;

COMMENT ON INDEX public.uq_app_analytics_deal_viewed_daily IS
  'Idempotency backstop: collapses repeat deal_viewed impressions to one per user/device/deal/UTC-day.';


-- ============================================================
-- Source migration: 20260708130000_nearby_geo_rpcs.sql
-- ============================================================

-- Server-side geo filtering for the consumer feed.
--
-- The home feed loaded every business page-by-page and filtered by distance in JS,
-- which does not scale past a few hundred shops. These RPCs push the radius filter
-- (and ordering + pagination) into Postgres using an indexed bounding-box pre-filter
-- refined by a great-circle distance. No PostGIS extension required, so this works on
-- any Supabase project; swap to geography/ST_DWithin later if desired.
--
-- Favorites override distance: callers pass p_favorite_ids and those rows are always
-- included regardless of radius (matches the existing client behavior).

-- Btree index backs the latitude/longitude range scan in the bounding-box pre-filter.
CREATE INDEX IF NOT EXISTS idx_businesses_lat_lng
  ON public.businesses (latitude, longitude)
  WHERE latitude IS NOT NULL AND longitude IS NOT NULL;

-- Great-circle distance in statute miles. IMMUTABLE so it can be inlined/indexed.
CREATE OR REPLACE FUNCTION public.haversine_miles(
  lat1 double precision,
  lng1 double precision,
  lat2 double precision,
  lng2 double precision
) RETURNS double precision
LANGUAGE sql IMMUTABLE PARALLEL SAFE AS $$
  SELECT 3958.7558657441 * 2 * asin(sqrt(
    power(sin(radians(lat2 - lat1) / 2), 2)
    + cos(radians(lat1)) * cos(radians(lat2)) * power(sin(radians(lng2 - lng1) / 2), 2)
  ));
$$;

-- Businesses within p_radius_miles of (p_lat, p_lng), nearest first, plus any favorites.
CREATE OR REPLACE FUNCTION public.nearby_businesses(
  p_lat double precision,
  p_lng double precision,
  p_radius_miles double precision DEFAULT 15,
  p_limit integer DEFAULT 50,
  p_offset integer DEFAULT 0,
  p_favorite_ids uuid[] DEFAULT '{}'
) RETURNS TABLE (
  id uuid,
  name text,
  location text,
  latitude numeric,
  longitude numeric,
  distance_miles double precision
)
LANGUAGE sql STABLE AS $$
  WITH bounds AS (
    SELECT
      p_radius_miles / 69.0 AS dlat,
      -- guard against div-by-zero near the poles; DFW is ~33N so cos is ~0.84
      p_radius_miles / (69.0 * GREATEST(cos(radians(p_lat)), 0.01)) AS dlng
  )
  SELECT
    b.id, b.name, b.location, b.latitude, b.longitude,
    public.haversine_miles(p_lat, p_lng, b.latitude::double precision, b.longitude::double precision) AS distance_miles
  FROM public.businesses b, bounds
  WHERE b.latitude IS NOT NULL AND b.longitude IS NOT NULL
    AND (
      b.id = ANY(p_favorite_ids)
      OR (
        b.latitude BETWEEN p_lat - bounds.dlat AND p_lat + bounds.dlat
        AND b.longitude BETWEEN p_lng - bounds.dlng AND p_lng + bounds.dlng
        AND public.haversine_miles(p_lat, p_lng, b.latitude::double precision, b.longitude::double precision) <= p_radius_miles
      )
    )
  ORDER BY distance_miles ASC
  LIMIT GREATEST(p_limit, 0) OFFSET GREATEST(p_offset, 0);
$$;

-- Active deal IDs whose business is within radius (or favorited), nearest first.
-- Returns IDs only so callers hydrate full rows with their existing select (keeping
-- the deal shape in one place); recurring-window refinement stays client-side.
CREATE OR REPLACE FUNCTION public.nearby_deals(
  p_lat double precision,
  p_lng double precision,
  p_radius_miles double precision DEFAULT 15,
  p_limit integer DEFAULT 80,
  p_offset integer DEFAULT 0,
  p_favorite_ids uuid[] DEFAULT '{}'
) RETURNS TABLE (
  id uuid,
  business_id uuid,
  distance_miles double precision
)
LANGUAGE sql STABLE AS $$
  WITH bounds AS (
    SELECT
      p_radius_miles / 69.0 AS dlat,
      p_radius_miles / (69.0 * GREATEST(cos(radians(p_lat)), 0.01)) AS dlng
  )
  SELECT
    d.id, d.business_id,
    public.haversine_miles(p_lat, p_lng, b.latitude::double precision, b.longitude::double precision) AS distance_miles
  FROM public.deals d
  JOIN public.businesses b ON b.id = d.business_id
  , bounds
  WHERE d.is_active = true
    AND d.end_time >= now()
    AND b.latitude IS NOT NULL AND b.longitude IS NOT NULL
    AND (
      b.id = ANY(p_favorite_ids)
      OR (
        b.latitude BETWEEN p_lat - bounds.dlat AND p_lat + bounds.dlat
        AND b.longitude BETWEEN p_lng - bounds.dlng AND p_lng + bounds.dlng
        AND public.haversine_miles(p_lat, p_lng, b.latitude::double precision, b.longitude::double precision) <= p_radius_miles
      )
    )
  ORDER BY distance_miles ASC, d.end_time ASC
  LIMIT GREATEST(p_limit, 0) OFFSET GREATEST(p_offset, 0);
$$;

GRANT EXECUTE ON FUNCTION public.haversine_miles(double precision, double precision, double precision, double precision) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION public.nearby_businesses(double precision, double precision, double precision, integer, integer, uuid[]) TO anon, authenticated;
GRANT EXECUTE ON FUNCTION public.nearby_deals(double precision, double precision, double precision, integer, integer, uuid[]) TO anon, authenticated;


-- ============================================================
-- Source migration: 20260708140000_consumer_deal_alerts_enabled.sql
-- ============================================================

-- Server-side mirror of the consumer's in-app "deal alerts" toggle.
--
-- The opt-in flag lives in the client's secure store (getAlertsEnabled). Server-sent
-- pushes can't read that, so we sync it here and require it true before targeting a
-- user with the weekly digest. Defaults false (opt-in).
ALTER TABLE public.consumer_profiles
  ADD COLUMN IF NOT EXISTS deal_alerts_enabled boolean NOT NULL DEFAULT false;

COMMENT ON COLUMN public.consumer_profiles.deal_alerts_enabled IS
  'Mirrors the app deal-alerts opt-in (synced from the client). Weekly-digest targeting requires this = true.';


-- ============================================================
-- Source migration: 20260710120000_deal_shares.sql
-- ============================================================

-- Share Deal MVP: per-user, per-deal share codes.
--
-- A share is not a transfer. The sender's claim code is never stored here
-- and never sent to friends. Friends use the public share URL to claim their
-- own offer through the separate website repo.

BEGIN;

CREATE TABLE IF NOT EXISTS public.deal_shares (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  share_code text NOT NULL,
  deal_id uuid NOT NULL REFERENCES public.deals(id) ON DELETE CASCADE,
  shared_by_user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  created_at timestamptz NOT NULL DEFAULT now(),
  opened_count integer NOT NULL DEFAULT 0,
  first_opened_at timestamptz NULL,
  last_opened_at timestamptz NULL
);

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'deal_shares_share_code_key'
      AND conrelid = 'public.deal_shares'::regclass
  ) THEN
    ALTER TABLE public.deal_shares
      ADD CONSTRAINT deal_shares_share_code_key UNIQUE (share_code);
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'deal_shares_sender_deal_key'
      AND conrelid = 'public.deal_shares'::regclass
  ) THEN
    ALTER TABLE public.deal_shares
      ADD CONSTRAINT deal_shares_sender_deal_key UNIQUE (shared_by_user_id, deal_id);
  END IF;
END $$;

ALTER TABLE public.deal_shares ENABLE ROW LEVEL SECURITY;

REVOKE ALL ON public.deal_shares FROM anon, authenticated;

GRANT SELECT (
  id,
  share_code,
  deal_id,
  shared_by_user_id,
  created_at,
  opened_count,
  first_opened_at,
  last_opened_at
) ON public.deal_shares TO authenticated;

GRANT INSERT (
  share_code,
  deal_id,
  shared_by_user_id
) ON public.deal_shares TO authenticated;

-- Public previews use lookup_deal_share(); do not expose deal_shares directly.
DROP POLICY IF EXISTS deal_shares_public_preview_read ON public.deal_shares;

-- Senders can read their own share rows.
DROP POLICY IF EXISTS deal_shares_self_read ON public.deal_shares;
CREATE POLICY deal_shares_self_read
  ON public.deal_shares FOR SELECT
  TO authenticated
  USING (auth.uid() = shared_by_user_id);

-- Senders can create their own share rows. Updates and deletes stay blocked.
DROP POLICY IF EXISTS deal_shares_self_insert ON public.deal_shares;
CREATE POLICY deal_shares_self_insert
  ON public.deal_shares FOR INSERT
  TO authenticated
  WITH CHECK (auth.uid() = shared_by_user_id);

CREATE OR REPLACE FUNCTION public.lookup_deal_share(lookup_code text)
RETURNS TABLE (
  share_status text,
  share_code text,
  deal_id uuid,
  deal_title text,
  deal_description text,
  deal_start_time timestamptz,
  deal_end_time timestamptz,
  deal_max_claims integer,
  deal_price numeric,
  deal_poster_url text,
  deal_poster_storage_path text,
  business_name text,
  business_address text,
  business_location text,
  business_phone text,
  business_hours_text text,
  business_logo_url text,
  opened_count integer
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  normalized_code text := upper(trim(coalesce(lookup_code, '')));
  share_row public.deal_shares%ROWTYPE;
BEGIN
  IF normalized_code !~ '^[ABCDEFGHJKMNPQRSTUVWXYZ23456789]{7}$' THEN
    RETURN QUERY
    SELECT
      'invalid'::text,
      normalized_code,
      NULL::uuid,
      NULL::text,
      NULL::text,
      NULL::timestamptz,
      NULL::timestamptz,
      NULL::integer,
      NULL::numeric,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::integer;
    RETURN;
  END IF;

  UPDATE public.deal_shares ds
  SET
    opened_count = ds.opened_count + 1,
    first_opened_at = coalesce(ds.first_opened_at, now()),
    last_opened_at = now()
  WHERE ds.share_code = normalized_code
  RETURNING ds.*
  INTO share_row;

  IF NOT FOUND THEN
    RETURN QUERY
    SELECT
      'not_found'::text,
      normalized_code,
      NULL::uuid,
      NULL::text,
      NULL::text,
      NULL::timestamptz,
      NULL::timestamptz,
      NULL::integer,
      NULL::numeric,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::integer;
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    CASE
      WHEN d.is_active IS DISTINCT FROM true
        OR d.start_time > now()
        OR d.end_time <= now()
        THEN 'expired'::text
      ELSE 'valid'::text
    END AS share_status,
    share_row.share_code,
    d.id,
    d.title,
    d.description,
    d.start_time,
    d.end_time,
    d.max_claims,
    d.price,
    d.poster_url,
    d.poster_storage_path,
    b.name,
    b.address,
    b.location,
    b.phone,
    b.hours_text,
    b.logo_url,
    share_row.opened_count
  FROM public.deals d
  JOIN public.businesses b ON b.id = d.business_id
  WHERE d.id = share_row.deal_id;

  IF NOT FOUND THEN
    RETURN QUERY
    SELECT
      'not_found'::text,
      share_row.share_code,
      NULL::uuid,
      NULL::text,
      NULL::text,
      NULL::timestamptz,
      NULL::timestamptz,
      NULL::integer,
      NULL::numeric,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      share_row.opened_count;
  END IF;
END;
$$;

REVOKE EXECUTE ON FUNCTION public.lookup_deal_share(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.lookup_deal_share(text) TO anon;

COMMENT ON FUNCTION public.lookup_deal_share(text)
  IS 'Public Share Deal preview lookup. Normalizes a share code, increments open counters for found shares, and returns only public-safe deal/business preview fields.';

COMMIT;


-- ============================================================
-- Source migration: 20260711120000_profiles_role.sql
-- ============================================================

-- Hard Shopper/Business role split (spec section 4, item 2, decided 2026-06-10).
-- The role is picked once at signup and never changes. `app_tab_mode` stays for
-- old installed builds that still upsert it, but routing no longer reads it.
--
-- DO NOT APPLY without Dan's explicit approval (hard gate). Must be applied
-- before the role-split build ships; the client falls back to deriving the
-- role from `businesses` ownership until then.

ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS role TEXT CHECK (role IN ('customer', 'business'));

COMMENT ON COLUMN public.profiles.role IS
  'Permanent account role chosen at signup: customer (Shopper) or business. Replaces app_tab_mode for routing.';

-- Existing accounts derive their permanent role from data:
-- owns a businesses row -> business, otherwise customer. app_tab_mode is
-- ignored because the old build reset it to ''customer'' on every sign-out.
UPDATE public.profiles p
SET role = CASE
  WHEN EXISTS (SELECT 1 FROM public.businesses b WHERE b.owner_id = p.id) THEN 'business'
  ELSE 'customer'
END
WHERE p.role IS NULL;

-- Business owners whose profiles row was never created (profiles rows were
-- only written by the old client upsert) still need a role to land on.
INSERT INTO public.profiles (id, role)
SELECT DISTINCT b.owner_id, 'business'
FROM public.businesses b
WHERE b.owner_id IS NOT NULL
ON CONFLICT (id) DO UPDATE SET role = EXCLUDED.role WHERE public.profiles.role IS NULL;


