-- Source migration: 20260713120000_business_claim_notifications.sql
-- ============================================================

-- Minimum business notifications (spec 11.8): new-claim and sold-out owner pushes.
--
-- 1. businesses.claim_notifications_enabled — owner-side preference, default ON.
--    The owner toggles it from the business Account screen; the claim-deal edge
--    function checks it before sending any owner push. The explicit column-level
--    SELECT grant is required because 20260705120000_businesses_pii_column_grants.sql
--    replaced the table-level SELECT grant with an explicit column list.
--    (UPDATE was never column-restricted, so the existing owner-update RLS policy
--    already covers writes to the new column.)
-- 2. deals.claim_push_last_sent_at — suppression-window state so a burst of claims
--    sends at most one "new claim" push per deal per 10-minute window. Written by
--    the claim-deal edge function (service role) only; clients never touch it.

ALTER TABLE public.businesses
  ADD COLUMN IF NOT EXISTS claim_notifications_enabled BOOLEAN NOT NULL DEFAULT TRUE;

COMMENT ON COLUMN public.businesses.claim_notifications_enabled IS
  'Owner push notifications for new claims / sold-out deals. Default on; toggled from the business Account screen.';

GRANT SELECT (claim_notifications_enabled) ON public.businesses TO authenticated;

ALTER TABLE public.deals
  ADD COLUMN IF NOT EXISTS claim_push_last_sent_at TIMESTAMPTZ;

COMMENT ON COLUMN public.deals.claim_push_last_sent_at IS
  'Last time a "new claim" owner push was sent for this deal (suppression window). Service-role writes only (claim-deal edge function).';


-- ============================================================
-- Source migration: 20260714120000_fix_purge_user_data_columns.sql
-- ============================================================

-- Corrective rewrite of purge_user_data (original: 20260705120008_purge_user_data_rpc.sql).
--
-- The original function runs
--   UPDATE public.app_analytics_events SET user_id = NULL, session_id = NULL ...
-- but app_analytics_events has never had a session_id column — not in any repo
-- migration and (prod-probed 2026-06-10, scripts/probe-analytics-schema.mjs)
-- not in production either. Its EXCEPTION handler only catches undefined_table,
-- so the function raises 42703 (undefined_column) on EVERY call, and account
-- deletion always fell through to the FK cascade (hard-deleting deal_claims and
-- shrinking merchant dashboard history) instead of anonymizing.
--
-- Changes from the original, everything else preserved verbatim:
--   1. Drop the nonexistent app_analytics_events.session_id reference.
--   2. Additionally clear deal_claims.session_id_at_claim (a real column, added
--      in 20260327120000) — a pseudonymous identifier the original left behind
--      on anonymized claims.

CREATE OR REPLACE FUNCTION public.purge_user_data(p_user_id uuid)
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Anonymize claim history (preserve aggregate analytics; remove personal link).
  UPDATE public.deal_claims
    SET user_id = NULL,
        zip_at_claim = NULL,
        location_source_at_claim = NULL,
        session_id_at_claim = NULL
    WHERE user_id = p_user_id;

  -- Anonymize raw analytics events (keep the row for merchant dashboards but drop the link).
  UPDATE public.app_analytics_events
    SET user_id = NULL
    WHERE user_id = p_user_id;

  -- Hard-delete tables that exist purely for the user.
  DELETE FROM public.favorites WHERE user_id = p_user_id;
  DELETE FROM public.push_tokens WHERE user_id = p_user_id;
  DELETE FROM public.consumer_profiles WHERE user_id = p_user_id;

  EXECUTE 'DELETE FROM public.consumer_push_prefs WHERE user_id = $1'
    USING p_user_id;
EXCEPTION
  WHEN undefined_table THEN
    -- Table may not exist in all environments; ignore.
    NULL;
END;
$$;

-- Supabase default privileges grant EXECUTE to anon/authenticated on every new
-- function, and REVOKE FROM PUBLIC does not remove those explicit grants.
REVOKE EXECUTE ON FUNCTION public.purge_user_data(uuid) FROM PUBLIC, anon, authenticated;
GRANT EXECUTE ON FUNCTION public.purge_user_data(uuid) TO service_role;

COMMENT ON FUNCTION public.purge_user_data(uuid)
  IS 'Anonymizes or deletes all rows tied to a given auth user. Called by delete-user-account before auth.admin.deleteUser. Service role only.';


-- ============================================================
-- Source migration: 20260715120000_share_lookup_hardening.sql
-- ============================================================

-- Share Deal hardening (audit follow-ups). Two changes:
--
-- 1. lookup_deal_share: throttle the anonymous opened_count increment to one
--    bump per share row per 30 seconds. The RPC is anon-callable, so without
--    this any visitor could spam-inflate a sender's open counter. The preview
--    itself is unaffected — when the bump is throttled the row is re-read and
--    the response is identical, just without the counter write.
-- 2. deal_shares insert policy: senders can only mint codes for live deals
--    (active, started, not ended). Previously any authenticated user could
--    insert a share row for ANY deal id, including not-yet-live deals.
--
-- Function body is otherwise identical to 20260710120000_deal_shares.sql.

BEGIN;

CREATE OR REPLACE FUNCTION public.lookup_deal_share(lookup_code text)
RETURNS TABLE (
  share_status text,
  share_code text,
  deal_id uuid,
  deal_title text,
  deal_description text,
  deal_start_time timestamptz,
  deal_end_time timestamptz,
  deal_max_claims integer,
  deal_price numeric,
  deal_poster_url text,
  deal_poster_storage_path text,
  business_name text,
  business_address text,
  business_location text,
  business_phone text,
  business_hours_text text,
  business_logo_url text,
  opened_count integer
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  normalized_code text := upper(trim(coalesce(lookup_code, '')));
  share_row public.deal_shares%ROWTYPE;
BEGIN
  IF normalized_code !~ '^[ABCDEFGHJKMNPQRSTUVWXYZ23456789]{7}$' THEN
    RETURN QUERY
    SELECT
      'invalid'::text,
      normalized_code,
      NULL::uuid,
      NULL::text,
      NULL::text,
      NULL::timestamptz,
      NULL::timestamptz,
      NULL::integer,
      NULL::numeric,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::integer;
    RETURN;
  END IF;

  -- Throttled counter bump: at most one increment per row per 30 seconds.
  UPDATE public.deal_shares ds
  SET
    opened_count = ds.opened_count + 1,
    first_opened_at = coalesce(ds.first_opened_at, now()),
    last_opened_at = now()
  WHERE ds.share_code = normalized_code
    AND (ds.last_opened_at IS NULL OR ds.last_opened_at < now() - interval '30 seconds')
  RETURNING ds.*
  INTO share_row;

  -- Throttled (row exists but was bumped recently) or genuinely missing —
  -- re-read so the preview still works when only the bump was skipped.
  IF NOT FOUND THEN
    SELECT ds.* INTO share_row
    FROM public.deal_shares ds
    WHERE ds.share_code = normalized_code;
  END IF;

  IF share_row.id IS NULL THEN
    RETURN QUERY
    SELECT
      'not_found'::text,
      normalized_code,
      NULL::uuid,
      NULL::text,
      NULL::text,
      NULL::timestamptz,
      NULL::timestamptz,
      NULL::integer,
      NULL::numeric,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::integer;
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    CASE
      WHEN d.is_active IS DISTINCT FROM true
        OR d.start_time > now()
        OR d.end_time <= now()
        THEN 'expired'::text
      ELSE 'valid'::text
    END AS share_status,
    share_row.share_code,
    d.id,
    d.title,
    d.description,
    d.start_time,
    d.end_time,
    d.max_claims,
    d.price,
    d.poster_url,
    d.poster_storage_path,
    b.name,
    b.address,
    b.location,
    b.phone,
    b.hours_text,
    b.logo_url,
    share_row.opened_count
  FROM public.deals d
  JOIN public.businesses b ON b.id = d.business_id
  WHERE d.id = share_row.deal_id;

  IF NOT FOUND THEN
    RETURN QUERY
    SELECT
      'not_found'::text,
      share_row.share_code,
      NULL::uuid,
      NULL::text,
      NULL::text,
      NULL::timestamptz,
      NULL::timestamptz,
      NULL::integer,
      NULL::numeric,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      NULL::text,
      share_row.opened_count;
  END IF;
END;
$$;

REVOKE EXECUTE ON FUNCTION public.lookup_deal_share(text) FROM PUBLIC;
GRANT EXECUTE ON FUNCTION public.lookup_deal_share(text) TO anon;

COMMENT ON FUNCTION public.lookup_deal_share(text)
  IS 'Public Share Deal preview lookup. Normalizes a share code, increments open counters (throttled to one bump per 30s per share) for found shares, and returns only public-safe deal/business preview fields.';

-- Senders can only mint share codes for live deals they can see.
DROP POLICY IF EXISTS deal_shares_self_insert ON public.deal_shares;
CREATE POLICY deal_shares_self_insert
  ON public.deal_shares FOR INSERT
  TO authenticated
  WITH CHECK (
    auth.uid() = shared_by_user_id
    AND EXISTS (
      SELECT 1 FROM public.deals d
      WHERE d.id = deal_id
        AND d.is_active = true
        AND (d.start_time IS NULL OR d.start_time <= now())
        AND d.end_time > now()
    )
  );

COMMIT;


-- ============================================================
-- Source migration: 20260716120000_deal_claim_counts_rpc.sql
-- ============================================================

-- Consumer-visible total claim counts, for scarcity UI ("Only N left") and
-- pre-rendered sold-out states.
--
-- deal_claims RLS only lets a user read their OWN claims (plus business owners
-- reading claims on their deals), so a client-side count over deal_claims sees
-- at most the caller's single claim. The deal detail screen's existing
-- "claims remaining" line has therefore always been computed from that
-- under-count. This aggregate-only SECURITY DEFINER function exposes the true
-- per-deal totals — counts only, never claim rows or user ids.

CREATE OR REPLACE FUNCTION public.deal_claim_counts(p_deal_ids uuid[])
RETURNS TABLE (deal_id uuid, claim_count integer)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT dc.deal_id, count(*)::integer AS claim_count
  FROM public.deal_claims dc
  WHERE cardinality(p_deal_ids) <= 200  -- bound the IN-list; feed asks for <= 80
    AND dc.deal_id = ANY (p_deal_ids)
    AND dc.claim_status IS DISTINCT FROM 'canceled'  -- match claim-deal's cap counting
  GROUP BY dc.deal_id;
$$;

-- Supabase default privileges grant EXECUTE to anon on every new function,
-- and REVOKE FROM PUBLIC does not remove that explicit grant.
REVOKE EXECUTE ON FUNCTION public.deal_claim_counts(uuid[]) FROM PUBLIC, anon;
GRANT EXECUTE ON FUNCTION public.deal_claim_counts(uuid[]) TO authenticated;

COMMENT ON FUNCTION public.deal_claim_counts(uuid[])
  IS 'Aggregate-only: non-canceled claim counts per deal id (max 200 ids). Used by the consumer feed and deal detail for scarcity/sold-out display.';


-- ============================================================
-- Source migration: 20260718120000_deal_source_locale_and_english_translation.sql
-- ============================================================

-- Track the language a business owner used to create a deal and store all
-- customer-facing deal copy in English, Spanish, and Korean.
--
-- Existing rows are treated as English source because the previous schema used
-- `title` / `description` as canonical English copy and only stored es/ko
-- translations.

ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS source_locale TEXT NOT NULL DEFAULT 'en';
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS title_en TEXT;
ALTER TABLE public.deals ADD COLUMN IF NOT EXISTS description_en TEXT;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM pg_constraint
    WHERE conname = 'deals_source_locale_check'
  ) THEN
    ALTER TABLE public.deals
      ADD CONSTRAINT deals_source_locale_check
      CHECK (source_locale IN ('en', 'es', 'ko'));
  END IF;
END $$;

UPDATE public.deals
SET
  source_locale = COALESCE(NULLIF(source_locale, ''), 'en'),
  title_en = COALESCE(NULLIF(title_en, ''), title),
  description_en = COALESCE(NULLIF(description_en, ''), description)
WHERE
  source_locale IS DISTINCT FROM COALESCE(NULLIF(source_locale, ''), 'en')
  OR title_en IS NULL
  OR title_en = ''
  OR description_en IS NULL
  OR description_en = '';

COMMENT ON COLUMN public.deals.source_locale
  IS 'Owner source language for editable deal copy: en, es, or ko.';
COMMENT ON COLUMN public.deals.title_en
  IS 'Customer-facing English deal title. For English source deals this mirrors title.';
COMMENT ON COLUMN public.deals.description_en
  IS 'Customer-facing English deal description. For English source deals this mirrors description.';


-- ============================================================
-- Source migration: 20260722120000_ai_generation_cost_ledger.sql
-- ============================================================

-- Private AI cost ledger. Written by service-role Edge Functions only.
-- Do not expose this table or its reporting views to mobile clients.

CREATE TABLE IF NOT EXISTS public.ai_generation_costs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  business_id UUID REFERENCES public.businesses (id) ON DELETE SET NULL,
  deal_id UUID REFERENCES public.deals (id) ON DELETE SET NULL,
  owner_user_id UUID,
  request_group_id UUID NOT NULL,
  feature TEXT NOT NULL,
  provider TEXT NOT NULL DEFAULT 'openai',
  model TEXT NOT NULL,
  endpoint TEXT NOT NULL,
  input_tokens INTEGER NOT NULL DEFAULT 0,
  cached_input_tokens INTEGER NOT NULL DEFAULT 0,
  output_tokens INTEGER NOT NULL DEFAULT 0,
  image_input_tokens INTEGER NOT NULL DEFAULT 0,
  image_output_tokens INTEGER NOT NULL DEFAULT 0,
  image_text_input_tokens INTEGER NOT NULL DEFAULT 0,
  audio_seconds NUMERIC NOT NULL DEFAULT 0,
  web_search_calls INTEGER NOT NULL DEFAULT 0,
  estimated_cost_usd NUMERIC(12,6) NOT NULL DEFAULT 0,
  openai_request_id TEXT,
  response_id TEXT,
  success BOOLEAN NOT NULL DEFAULT true,
  error_code TEXT,
  error_message TEXT,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_ai_generation_costs_request_group
  ON public.ai_generation_costs (request_group_id, created_at);

CREATE INDEX IF NOT EXISTS idx_ai_generation_costs_business_created
  ON public.ai_generation_costs (business_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_ai_generation_costs_deal_created
  ON public.ai_generation_costs (deal_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_ai_generation_costs_feature_created
  ON public.ai_generation_costs (feature, created_at DESC);

ALTER TABLE public.ai_generation_costs ENABLE ROW LEVEL SECURITY;

REVOKE ALL ON public.ai_generation_costs FROM anon, authenticated;
GRANT SELECT, INSERT ON public.ai_generation_costs TO service_role;

COMMENT ON TABLE public.ai_generation_costs IS
  'Private internal AI cost ledger. RLS has no client policies; service role/admin only.';

CREATE OR REPLACE VIEW public.ai_generation_cost_daily AS
SELECT
  date_trunc('day', created_at)::date AS day,
  SUM(estimated_cost_usd)::numeric(12,6) AS total_ai_cost_usd,
  COUNT(DISTINCT request_group_id) AS generated_ad_attempts,
  CASE
    WHEN COUNT(DISTINCT request_group_id) = 0 THEN 0::numeric(12,6)
    ELSE (SUM(estimated_cost_usd) / COUNT(DISTINCT request_group_id))::numeric(12,6)
  END AS average_cost_per_generated_ad,
  SUM(web_search_calls)::integer AS web_search_calls,
  COUNT(*) FILTER (WHERE endpoint IN ('images.generations', 'images.edits')) AS image_generation_calls,
  COUNT(*) FILTER (WHERE success = false) AS failed_or_retried_calls
FROM public.ai_generation_costs
GROUP BY 1;

CREATE OR REPLACE VIEW public.ai_generation_cost_by_business AS
SELECT
  business_id,
  SUM(estimated_cost_usd)::numeric(12,6) AS total_ai_cost_usd,
  COUNT(DISTINCT request_group_id) AS generated_ad_attempts,
  SUM(web_search_calls)::integer AS web_search_calls,
  COUNT(*) FILTER (WHERE endpoint IN ('images.generations', 'images.edits')) AS image_generation_calls,
  COUNT(*) FILTER (WHERE success = false) AS failed_or_retried_calls
FROM public.ai_generation_costs
GROUP BY business_id;

CREATE OR REPLACE VIEW public.ai_generation_cost_by_deal AS
SELECT
  deal_id,
  SUM(estimated_cost_usd)::numeric(12,6) AS total_ai_cost_usd,
  COUNT(DISTINCT request_group_id) AS generated_ad_attempts,
  SUM(web_search_calls)::integer AS web_search_calls,
  COUNT(*) FILTER (WHERE endpoint IN ('images.generations', 'images.edits')) AS image_generation_calls,
  COUNT(*) FILTER (WHERE success = false) AS failed_or_retried_calls
FROM public.ai_generation_costs
GROUP BY deal_id;

CREATE OR REPLACE VIEW public.ai_generation_cost_by_feature_model AS
SELECT
  feature,
  model,
  endpoint,
  SUM(estimated_cost_usd)::numeric(12,6) AS total_ai_cost_usd,
  COUNT(*) AS call_count,
  SUM(web_search_calls)::integer AS web_search_calls,
  COUNT(*) FILTER (WHERE success = false) AS failed_or_retried_calls
FROM public.ai_generation_costs
GROUP BY feature, model, endpoint;

REVOKE ALL ON public.ai_generation_cost_daily FROM anon, authenticated;
REVOKE ALL ON public.ai_generation_cost_by_business FROM anon, authenticated;
REVOKE ALL ON public.ai_generation_cost_by_deal FROM anon, authenticated;
REVOKE ALL ON public.ai_generation_cost_by_feature_model FROM anon, authenticated;

